terraform plan>

 resource "azurerm_lb_backend_address_pool" "azurelbbackend" {
 id = "/subscriptions/XXXXXXXXXX/resourceGroups/XXXXXX/providers/Microsoft.Network/loadBalancers/XXXXX/backendAddressPools/XXXXXX"
 name = "XXXXXX"
 # (5 unchanged attributes hidden)

 - backend_address {
 - name = "XXXXXXX" -> null
 }
 }

